def _split_parts(text):
    cleaned = text.replace("/", " ").replace("-", " ").replace("(", " ").replace(")", " ")
    return [part for part in cleaned.split() if part]


def _parse_pairs(raw):
    return [tuple(part.split("=", 1)) for part in raw.split("|") if part]


def _make_cs_entry(idx, level, cat, icon, word, tr, wt="noun"):
    return {
        "id": idx,
        "mod": "cs",
        "level": level,
        "cat": cat,
        "icon": icon,
        "word": word,
        "syl": _split_parts(word),
        "ph": "",
        "wt": wt,
        "tr": tr,
        "tpl": "The ___ is important in computer English.",
        "sent": f"<strong>{word}</strong> is a useful computer English term for {cat.lower()}.",
        "str": "S+V+O",
        "rel": [],
        "why": f"{word} is a common {cat.lower()} term in tech conversations.",
        "da": f"What does {word} mean in tech?",
        "db": f"It means {tr.lower()}."
    }


