def _build_extra_cs_words():
    items = []
    next_id = 1251
    for level, cat, icon, raw in _CS_EXTRA_GROUPS:
        for word, tr in _parse_pairs(raw):
            items.append(_make_cs_entry(next_id, level, cat, icon, word, tr))
            next_id += 1
    return items


CS_WORDS.extend(_build_extra_cs_words())
assert len(CS_WORDS) == 500, f"Expected 500 CS words, found {len(CS_WORDS)}"
